VALUES
  ('optician-moex-02299', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是理想的硬式透氣隱形眼鏡驗配參考指標？', '["中心定位正確", "鏡片不小於虹膜直徑（horizontal visible iris diameter, HVID）", "眨眼時鏡片在垂直面上平滑順暢的滑動", "鏡片服貼吻合"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02300', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在驗配軟式隱形眼鏡時，下列那一項檢查不是必須執行的？', '["鏡片是否完全覆蓋角膜", "鏡片中心定位", "戴著鏡片時的角膜弧度儀（keratometry）檢查", "眨眼後的鏡片滑動情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02301', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一患者框架眼鏡的屈光度為-9.00 DS，角膜頂點距離為12 mm，此患者選擇配戴隱形眼鏡時，則隱形眼鏡 最接近的度數應為多少？', '["-8.00 DS", "-8.75 DS", "-9.50 DS", "-10.00 DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02302', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '正常的角膜的弧度最常為何種情況？', '["中間較平周圍較陡", "中間較陡周圍較平", "從中間至周圍的弧度不變", "沒有定論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02303', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於角膜弧度之測量，下列敘述何者錯誤？', '["角膜曲率可用曲率半徑r，單位為毫米mm，或屈光度，單位為Diopter, D來表示", "兩條互為垂直主經線的屈光度不同時，代表可能有角膜散光的存在", "角膜散光與自動驗光儀量出來的散光屈光度不同時，驗配隱形眼鏡的散光度數，要以角膜弧度儀為準", "角膜的頂點，角膜弧度儀無法直接量測，因此若角膜頂點偏移，則可能角膜弧度測量不準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02304', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於細隙燈顯微鏡（slit-lamp microscopy）的檢查，下列敘述何者錯誤？', '["直接焦點照射法（direct focal illumination）是最常用來觀察眼部透明組織的方法", "鏡面反射照射法（specular reflection）在光線照射角度垂直角膜時，最容易觀察到內皮細胞型態和病變", "直接後部反光照射法（direct retroillumination），可觀察角膜周邊新生血管", "間接後部反光照射法（indirect retroillumination），可看到角膜上皮水腫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02305', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '配戴硬式隱形眼鏡在角膜產生3點鐘與9點鐘方位的螢光染色現象，下列何者為最常見之原因？', '["角膜感染", "角膜水腫", "角膜乾燥", "角膜缺氧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02306', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一配戴隱形眼鏡者，抱怨常視力模糊、且有時會看到光暈及畏光或火花光感（sparky apperance），經 裂隙燈檢查發現角膜有淡灰白色霧狀及輕微角膜染色（corneal staining）和上皮表面粗糙，無分泌物、不 會疼痛，下列何種隱形眼鏡的併發症最有可能？', '["角膜內皮水腫（endothelial edema）", "角膜上皮微囊（epithelial microcysts）", "角膜上皮水腫（epithelial edema）", "角膜淺凹（dellen）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02307', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於棘狀阿米巴角膜炎的敘述，下列何者錯誤？', '["好發於隱形眼鏡清潔習慣不良的配戴者", "對大多數抗生素有效", "病程初期，容易與疱疹性角膜炎混淆", "病程後期角膜可出現環狀浸潤（ring infiltration）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02308', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於配戴隱形眼鏡後產生周邊角膜3點鐘及9點鐘的位置角膜螢光染色，下列敘述何者錯誤？', '["是配戴硬式隱形眼鏡最常發生的併發症之一", "大部分是因為機械性的摩擦所造成，要修緊邊弧減少鏡片滑動摩擦來改善", "可改用非球面設計，減少邊緣翹角可改善", "鏡片邊緣角膜乾燥也會發生，增加邊弧的淚液交換可改善"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
